def translate_category(cat: str, lang: str = "en") -> str:
    """Return the display label for a category in the requested language.

    The stored *cat* value is always the canonical English string;
    this function provides a visual DE translation only.
    """
    if lang == "de" and cat in _CATEGORY_DE:
        return _CATEGORY_DE[cat]
    return cat


def get_category_lang_map(lang: str = "en") -> dict[str, str]:
    """Return the full EN→display mapping for the given language.

    Used to inject a JS translation map into the page for the inline
    category editor.
    """
    if lang == "de":
        return dict(_CATEGORY_DE)
    return {}

def t(key: str, lang: str = "de") -> str:
    """Look up a translation. Falls back to English, then to the key itself."""
    entry = _TRANSLATIONS.get(key)
    if entry is None:
        return key
    return entry.get(lang, entry.get("en", key))


def get_lang_from_search(search: str = ""):
    """Extract an explicit language override from a query string."""
    try:
        lang = parse_qs((search or "").lstrip("?")).get("lang", [None])[0]
    except Exception:
        return None
    return lang if lang in ("en", "de") else None


def get_lang(lang_data) -> str:
    """Extract language string from a dcc.Store data value."""
    if isinstance(lang_data, dict):
        lang = lang_data.get("lang")
        if lang in ("en", "de"):
            return lang
    if isinstance(lang_data, str) and lang_data in ("en", "de"):
        return lang_data
    return "de"


def get_bankpilot_lang(lang_data=None, search: str = "") -> str:
    """Resolve BankPilot language with URL overrides taking priority."""
    url_lang = get_lang_from_search(search)
    if url_lang:
        return url_lang
    return get_lang(lang_data)
